import re
import json

clinical_data = env['data_3']
mutation_data = env['data_2']

mutated_barcodes = {row['ParticipantBarcode'] for row in mutation_data}

histology_counts = {}

for row in clinical_data:
    desc = row['Patient_description']
    histology = row['histological_type']

    if not histology or histology.startswith('['):
        continue

    match = re.search(r'TCGA-[A-Z0-9]{2}-[A-Z0-9]{4}', desc)
    if not match:
        continue

    barcode = match.group(0)

    if histology not in histology_counts:
        histology_counts[histology] = {'total': 0, 'mutated': 0}

    histology_counts[histology]['total'] += 1
    if barcode in mutated_barcodes:
        histology_counts[histology]['mutated'] += 1

results = []
for histology, counts in histology_counts.items():
    if counts['total'] > 0:
        pct = (counts['mutated'] / counts['total']) * 100
        results.append({'histology': histology, 'pct': pct, 'total': counts['total'], 'mutated': counts['mutated']})

results.sort(key=lambda x: x['pct'], reverse=True)

print(f"Total clinical rows: {len(clinical_data)}")
print(f"Total mutated barcodes: {len(mutated_barcodes)}")
print("Top 3 histological types by CDH1 mutation percentage:")
for i, r in enumerate(results[:3]):
    print(f"{i+1}. {r['histology']}: {r['pct']:.2f}% ({r['mutated']}/{r['total']})")

